#include <stdio.h>
#include <stdlib.h>

/*
 * Disjoint Set (Union-Find) Data Structure
 * Array Representation with Path Compression
 */

#define MAX_ELEMENTS 100

// Global parent array
int parent[MAX_ELEMENTS];
int rank[MAX_ELEMENTS];
int n; // Number of elements

// Function to initialize the disjoint set
void initialize(int numElements) {
 n = numElements;
 for (int i = 0; i < n; i++) {
 parent[i] = -1; // Each element is its own parent (root)
 rank[i] = 0; // Initialize rank to 0
 }
}

// Function to find parent with path compression
int findParent(int element) {
 // Base case: element is its own parent
 if (parent[element] == -1) {
 return element;
 }

 // Path compression: directly link to root
 parent[element] = findParent(parent[element]);
 return parent[element];
}

// Function to union two sets by rank
void unionSets(int element1, int element2) {
 int root1 = findParent(element1);
 int root2 = findParent(element2);

 // If already in same set, do nothing
 if (root1 == root2) {
 return;
 }

 // Union by rank: attach smaller rank tree under larger rank tree
 if (rank[root1] < rank[root2]) {
 parent[root1] = root2;
 } else if (rank[root1] > rank[root2]) {
 parent[root2] = root1;
 } else {
 // Same rank: choose one as root and increment its rank
 parent[root2] = root1;
 rank[root1]++;
 }
}

// Function to check if two elements are in the same set
int areInSameSet(int element1, int element2) {
 return findParent(element1) == findParent(element2);
}

// Function to display the current state
void display() {
 printf("\nElement: ");
 for (int i = 0; i < n; i++) {
 printf("%d ", i);
 }

 printf("\nParent: ");
 for (int i = 0; i < n; i++) {
 if (parent[i] == -1) {
 printf("- ");
 } else {
 printf("%d ", parent[i]);
 }
 }

 printf("\nRank: ");
 for (int i = 0; i < n; i++) {
 printf("%d ", rank[i]);
 }
 printf("\n");
}

// Main function to demonstrate operations
int main() {
 // Initialize disjoint set with 5 elements
 initialize(5);

 printf("=== Initial State ===");
 display();

 // Union operations
 printf("\n=== After Union(0, 1) ===");
 unionSets(0, 1);
 display();

 printf("\n=== After Union(2, 3) ===");
 unionSets(2, 3);
 display();

 printf("\n=== After Union(0, 2) ===");
 unionSets(0, 2); // Connect {0,1} with {2,3}
 display();

 // Find operations
 printf("\n=== Find Operations ===");
 printf("Parent of 0: %d\n", findParent(0));
 printf("Parent of 3: %d\n", findParent(3));
 printf("Parent of 4: %d\n", findParent(4));

 // Check if same set
 printf("\n=== Same Set Checks ===");
 printf("Are 0 and 3 in same set? %s\n", 
 areInSameSet(0, 3) ? "Yes" : "No");
 printf("Are 0 and 4 in same set? %s\n", 
 areInSameSet(0, 4) ? "Yes" : "No");

 return 0;
}
